using UnityEngine;
using UnityEngine.UI;
using System.Collections;

public class HealthBarUI : MonoBehaviour
{
    public Image healthBar;
    public Image healthBarBackground;
    public Text healthText;
    public Text percentageText;

    public float maxHealth = 100f;
    public float currentHealth = 100f;

    public float updateSpeed = 5f;
    private float targetFill;

    public Gradient healthGradient;

    void Start()
    {
        targetFill = currentHealth / maxHealth;
        UpdateHealthBar();
    }

    void Update()
    {
        // Smooth health bar transition
        if (healthBar != null)
        {
            healthBar.fillAmount = Mathf.Lerp(healthBar.fillAmount, targetFill, updateSpeed * Time.deltaTime);
        }
    }

    public void SetHealth(float health)
    {
        currentHealth = Mathf.Clamp(health, 0, maxHealth);
        targetFill = currentHealth / maxHealth;
        UpdateHealthBar();
    }

    public void TakeDamage(float damage)
    {
        currentHealth = Mathf.Clamp(currentHealth - damage, 0, maxHealth);
        targetFill = currentHealth / maxHealth;
        UpdateHealthBar();

        // Visual feedback: flash red
        StartCoroutine(FlashHealthBar());
    }

    public void Heal(float amount)
    {
        currentHealth = Mathf.Clamp(currentHealth + amount, 0, maxHealth);
        targetFill = currentHealth / maxHealth;
        UpdateHealthBar();
    }

    void UpdateHealthBar()
    {
        if (healthBar != null)
        {
            // Set fill amount
            healthBar.fillAmount = targetFill;

            // Set color based on health
            float healthPercent = currentHealth / maxHealth;
            healthBar.color = healthGradient.Evaluate(1 - healthPercent);
        }

        if (healthText != null)
        {
            healthText.text = currentHealth + " / " + maxHealth;
        }

        if (percentageText != null)
        {
            int percent = Mathf.RoundToInt((currentHealth / maxHealth) * 100);
            percentageText.text = percent + "%";
        }
    }

    IEnumerator FlashHealthBar()
    {
        if (healthBar != null)
        {
            // Flash red
            Color originalColor = healthBar.color;
            healthBar.color = Color.red;
            yield return new WaitForSeconds(0.1f);
            healthBar.color = originalColor;
        }
    }

    // Example: Smoothly decrease health
    public IEnumerator LoseHealthOverTime(float amount, float duration)
    {
        float startHealth = currentHealth;
        float elapsedTime = 0f;

        while (elapsedTime < duration)
        {
            elapsedTime += Time.deltaTime;
            float progress = elapsedTime / duration;
            float currentLoss = amount * progress;
            SetHealth(startHealth - currentLoss);
            yield return null;
        }

        SetHealth(startHealth - amount);
    }

    // Example: Check if health is critical
    public bool IsCritical()
    {
        return currentHealth < maxHealth * 0.25f;
    }

    // Example: Get health percentage
    public float GetHealthPercent()
    {
        return currentHealth / maxHealth;
    }
}

